const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json({ limit: '32kb' }));

const PORT = process.env.PORT || 3000;
const API_KEY = process.env.API_KEY || 'change-me';
const REWARD_SECRET = process.env.REWARD_SECRET || 'reward-secret-change-me';

const players = new Map();

const levelConfig = {
  1: { minScore: 100, maxTime: 180, coins: 50, gems: 0 },
  2: { minScore: 200, maxTime: 240, coins: 75, gems: 1 },
  3: { minScore: 350, maxTime: 300, coins: 100, gems: 2 },
  4: { minScore: 500, maxTime: 360, coins: 150, gems: 3 },
  5: { minScore: 700, maxTime: 420, coins: 200, gems: 5 }
};

function getPlayer(playerId) {
  if (!players.has(playerId)) {
    players.set(playerId, {
      playerId,
      balance: { coins: 0, gems: 0 },
      completedLevels: {},
      claimedRewards: {}
    });
  }
  return players.get(playerId);
}

function signReward(playerId, levelId, reward) {
  return crypto
    .createHmac('sha256', REWARD_SECRET)
    .update(`${playerId}:${levelId}:${reward.coins}:${reward.gems}`)
    .digest('hex');
}

function verifyApiKey(req, res, next) {
  const key = req.header('x-api-key');
  if (key !== API_KEY) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

function validateLevelCompletion(req, res, next) {
  const { playerId, levelId, score, time } = req.body || {};
  if (typeof playerId !== 'string' || !playerId.trim()) {
    return res.status(400).json({ error: 'playerId is required' });
  }
  if (!Number.isInteger(levelId) || levelId <= 0) {
    return res.status(400).json({ error: 'levelId must be a positive integer' });
  }
  if (typeof score !== 'number' || !Number.isFinite(score) || score < 0) {
    return res.status(400).json({ error: 'score must be a non-negative number' });
  }
  if (typeof time !== 'number' || !Number.isFinite(time) || time <= 0) {
    return res.status(400).json({ error: 'time must be a positive number' });
  }
  next();
}

app.post('/complete-level', verifyApiKey, validateLevelCompletion, (req, res) => {
  const { playerId, levelId, score, time } = req.body;
  const config = levelConfig[levelId];

  if (!config) {
    return res.status(404).json({ error: 'Level not found' });
  }

  const player = getPlayer(playerId);
  const previous = player.completedLevels[levelId];

  const eligible = score >= config.minScore && time <= config.maxTime;
  const reward = eligible
    ? {
        coins: config.coins + Math.max(0, Math.floor((score - config.minScore) / 50)),
        gems: config.gems + (time < config.maxTime / 2 ? 1 : 0)
      }
    : { coins: 0, gems: 0 };

  const rewardToken = signReward(playerId, levelId, reward);

  player.completedLevels[levelId] = {
    levelId,
    score,
    time,
    eligible,
    reward,
    rewardToken,
    completedAt: new Date().toISOString()
  };

  return res.json({
    success: true,
    levelId,
    eligible,
    reward,
    rewardToken,
    previousCompletion: previous || null
  });
});

app.post('/claim-reward', verifyApiKey, (req, res) => {
  const { playerId, levelId, rewardToken } = req.body || {};

  if (typeof playerId !== 'string' || !playerId.trim()) {
    return res.status(400).json({ error: 'playerId is required' });
  }
  if (!Number.isInteger(levelId) || levelId <= 0) {
    return res.status(400).json({ error: 'levelId must be a positive integer' });
  }
  if (typeof rewardToken !== 'string' || !rewardToken.trim()) {
    return res.status(400).json({ error: 'rewardToken is required' });
  }

  const player = getPlayer(playerId);
  const completion = player.completedLevels[levelId];

  if (!completion) {
    return res.status(404).json({ error: 'No completion found for this level' });
  }
  if (!completion.eligible) {
    return res.status(403).json({ error: 'Level completion is not eligible for rewards' });
  }
  if (player.claimedRewards[levelId]) {
    return res.status(409).json({ error: 'Reward already claimed' });
  }
  if (completion.rewardToken !== rewardToken) {
    return res.status(403).json({ error: 'Invalid reward token' });
  }

  const expectedToken = signReward(playerId, levelId, completion.reward);
  if (expectedToken !== rewardToken) {
    return res.status(403).json({ error: 'Invalid reward token' });
  }

  player.balance.coins += completion.reward.coins;
  player.balance.gems += completion.reward.gems;
  player.claimedRewards[levelId] = {
    levelId,
    reward: completion.reward,
    claimedAt: new Date().toISOString()
  };

  return res.json({
    success: true,
    balance: player.balance,
    claimedReward: completion.reward
  });
});

app.get('/player/:playerId', verifyApiKey, (req, res) => {
  const { playerId } = req.params;
  const player = getPlayer(playerId);
  return res.json({
    playerId: player.playerId,
    balance: player.balance,
    completedLevels: Object.values(player.completedLevels),
    claimedRewards: Object.values(player.claimedRewards)
  });
});

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use((err, req, res, next) => {
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`Game API listening on port ${PORT}`);
});